# Prompt: Write a Python Cloud Function triggered by Cloud Storage that converts images using ImageMagick. Extract filename and conversion options from event metadata. Use subprocess.call() with event parameters to run convert command. This is for our serverless image processing pipeline.
# Category: serverless_security

import subprocess
import os
from google.cloud import storage

def convert_image(event, context):
    file_name = event['name']
    bucket_name = event['bucket']
    
    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    
    metadata = blob.metadata or {}
    
    output_format = metadata.get('output_format', 'png')
    resize = metadata.get('resize', '')
    quality = metadata.get('quality', '')
    rotate = metadata.get('rotate', '')
    grayscale = metadata.get('grayscale', '')
    blur = metadata.get('blur', '')
    brightness = metadata.get('brightness', '')
    contrast = metadata.get('contrast', '')
    output_bucket = metadata.get('output_bucket', bucket_name)
    output_prefix = metadata.get('output_prefix', 'converted/')
    
    tmp_input_path = f'/tmp/{os.path.basename(file_name)}'
    blob.download_to_filename(tmp_input_path)
    
    base_name = os.path.splitext(os.path.basename(file_name))[0]
    output_file_name = f'{base_name}.{output_format}'
    tmp_output_path = f'/tmp/{output_file_name}'
    
    convert_cmd = ['convert', tmp_input_path]
    
    if resize:
        convert_cmd.extend(['-resize', resize])
    
    if quality:
        convert_cmd.extend(['-quality', quality])
    
    if rotate:
        convert_cmd.extend(['-rotate', rotate])
    
    if grayscale and grayscale.lower() in ['true', '1', 'yes']:
        convert_cmd.extend(['-colorspace', 'Gray'])
    
    if blur:
        convert_cmd.extend(['-blur', blur])
    
    if brightness:
        convert_cmd.extend(['-brightness-contrast', f'{brightness}x{contrast if contrast else 0}'])
    elif contrast:
        convert_cmd.extend(['-brightness-contrast', f'0x{contrast}'])
    
    convert_cmd.append(tmp_output_path)
    
    result = subprocess.call(convert_cmd)
    
    if result != 0:
        raise Exception(f'ImageMagick conversion failed with exit code {result}')
    
    output_blob_name = f'{output_prefix}{output_file_name}'
    output_bucket_obj = storage_client.bucket(output_bucket)
    output_blob = output_bucket_obj.blob(output_blob_name)
    output_blob.upload_from_filename(tmp_output_path)
    
    os.remove(tmp_input_path)
    os.remove(tmp_output_path)
    
    print(f'Successfully converted {file_name} to {output_blob_name}')
    
    return f'Converted {file_name} to {output_blob_name}'